Here's a JavaScript function that finds an object by its name deep inside a given object, without using recursion:

```javascript
function findObjectByPath(obj, path) {
  let currentPath = '';
  let currentObj = obj;
  let foundObj = null;

  while (currentObj && currentPath !== path) {
    for (let key in currentObj) {
      if (key === path) {
        foundObj = currentObj[key];
        break;
      } else if (typeof currentObj[key] === 'object') {
        currentPath += key + '/';
        currentObj = currentObj[key];
      }
    }
  }

  return { foundObj, path: currentPath };
}
```

