JavaScript:

```javascript
const sliderThumb = document.querySelector('.slider-thumb');
const sliderTrack = document.querySelector('.slider-track');

let radius = 50;

function updateSlider() {
  sliderThumb.style.transform = `translate(-50%, -50%)`;
  sliderTrack.style.width = `${radius * 2}px`;
  sliderTrack.style.height = `${radius * 2}px`;
}

updateSlider();

document.addEventListener('mouseup', () => {
  const mouseX = event.clientX;
  const mouseY = event.clientY;

  const thumbCenterX = radius + 10;
  const thumbCenterY = radius + 10;

  const deltaX = mouseX - thumbCenterX;
  const deltaY = mouseY - thumbCenterY;

  const newRadius = Math.sqrt(deltaX * deltaX + deltaY * deltaY) + 10;

  if (newRadius > 100) {
    newRadius = 100;
  }

  radius = newRadius;

  updateSlider();
});
```

