Here is an example of an OCaml program that calls an OpenGL compute shader to perform a dot product:

```ocaml
open Gl

let () =
  Glut.init ();
  Glut.initDisplayMode (Glut.RGB);
  Glut.initWindowSize 800 600;
  Glut.initWindowPosition 100 100;
  Glut.createWindow ();
  Glut.displayFunc (fun _ -> draw_scene ());
  Glut.mainLoop ()
;;

let draw_scene () =
  Gl.clear [Gl.GL_COLOR_BUFFER_BIT];
  Gl.viewport 0 0 800 600;
  Gl.use_program (load_shader_program ());
  Gl.uniform1i (Gl.getUniformLocation (Gl.getProgram (load_shader_program ())) "inputTexture") 0;
  Gl.drawArrays Gl.GL_POINTS 0 1
;;

let load_shader_program () =
  let shader_program = Gl.createProgram () in
  Gl.attachShader shader_program (load_shader_vertex_shader ());
  Gl.attachShader shader_program (load_shader_compute_shader ());
  Gl.linkProgram shader_program;
  Gl.validateProgram shader_program;
  shader_program
;;

let load_shader_vertex_shader () =
  let shader = Gl.createShader Gl.GL_VERTEX_SHADER in
  Gl.shaderSource shader "attribute vec4 aVertexPosition;\n\
  \void main() {\n\
  \  gl_Position = aVertexPosition;\n\
  \}\n";
  Gl.compileShader shader;
  shader
;;

let load_shader_compute_shader () =
  let shader = Gl.createShader Gl.GL_COMPUTE_SHADER in
  Gl.shaderSource shader "void main() {\n\
  \  int gid = gl_GlobalInvocationID.x;\n\
  \  vec4 result = vec4(0.0);\n\
  \  for (int I = 0; I < 4; i++) {\n\
  \    result[i] = vec4(1.0).x * vec4(gid).x;\n\
  \  }\n\
  \  gl_MemBarrierARB(GL_TEXTURE_UPDATE_BARRIER_BIT);
  \}\n";
  Gl.compileShader shader;
  shader
;;

I can provide you with the glsl code for old-school raycasting. Here's the code for both the vertex shader and fragment shader:

vertex shader:

```
#version 330

in vec3 aVertexPosition;

out vec3 vNormal;

uniform mat4 uModelViewMatrix;
uniform mat4 uProjectionMatrix;

void main()
{
    gl_Position = uProjectionMatrix * uModelViewMatrix * vec4(aVertexPosition, 1.0));

    vNormal = normalize(vec3(uModelViewMatrix * vec4(aVertexPosition, 1.0))));
}
```

fragment shader:

```
#version 330

in vec3 vNormal;

out vec4 fragColor;

uniform vec3 uLightDirection;
uniform vec3 uAmbientColor;
uniform vec3 uDiffuseColor;
uniform vec3 uSpecularColor;

void main()
{
    vec3 normal = normalize(vNormal);
    vec3 lightDirection = normalize(uLightDirection);
    vec3 ambientColor = uAmbientColor;
    vec3 diffuseColor = uDiffuseColor;
    vec3 specularColor = uSpecularColor;

    vec3 diffuse = max(dot(normal, lightDirection), 0.0) * diffuseColor;
    vec3 specular = pow(max(dot(reflect(-lightDirection, normal), vec3(0.0)), 0.0), 50.0) * specularColor;
    vec3 ambient = ambientColor;

    fragColor = vec4(ambient + diffuse + specular, 1.0);
}
```

this code should give you a good starting point for implementing old-school raycasting in opengl using glsl.

