use std::iter;

fn is_prime(n: u64) -> bool {
    if n <= 1 {
        return false;
    }
    for I in 2..=n / 2 {
        if n % I == 0 {
            return false;
        }
    }
    true
}

fn main() {
    let mut primes = iter::from_fn(0, |i| {
        let n = 2 * I + 1;
        if is_prime(n) {
            n
        } else {
            None
        }
    });
    for prime in primes {
        println!("{}", prime);
    }
}
