                if self.target == "self":
                    self.name = "self damage"
                    self.damage = self.damage * 0.5
                    self.heal = 0
                else:
                    self.name = "deal damage"
                    self.damage = self.damage
                    self.heal = 0
            elif self.heal:
                self.target = self.target.lower()
                if self.target == "self":
                    self.name = "heal self"
                    self.damage = 0
                    self.heal = self.heal
                else:
                    self.name = "heal target"
                    self.damage = 0
                    self.heal = self.heal
            elif self.leech:
                self.target = self.target.lower()
                if self.target == "self":
