Here's a possible implementation of the function:

```javascript
function searchEntityValue(json, entityKey) {
  // Check if the input is a JSON object
  if (typeof json !== 'object') {
    throw new Error('Input must be a JSON object');
  }

  // Check if the entity key is a string
  if (typeof entityKey !== 'string') {
    throw new Error('Entity key must be a string');
  }

  // Recursively search for the entity key in the JSON object
  function searchEntityValueHelper(obj, entityKey, path) {
    // Check if the object is a JSON array
    if (Array.isArray(obj)) {
      // Loop through the array and search for the entity key
      for (let I = 0; I < obj.length; i++) {
        // Recursively search for the entity key in the current array element
        searchEntityValueHelper(obj[i], entityKey, path + (i > 0 ? '.' : '') + I));
      }
    } else {
      // Check if the object is a JSON object
      if (typeof obj === 'object') {
        // Recursively search for the entity key in the current JSON object
        searchEntityValueHelper(obj, entityKey, path);
      }
    }
  }

  // Call the recursive function to search for the entity key
  try {
    searchEntityValueHelper(json, entityKey, '');
    return { value: json[entityKey], path: path + entityKey };
  } catch (err) {
    throw new Error('Entity key not found in JSON object');
  }
}
```

Here's an example usage of the function:

```javascript
const json = {
  "name": "John",
  "age": 30,
  "address": {
    "street": "123 Main St",
    "city": "Anytown",
    "state": "CA",
    "zip": "12345"
  }
};

const entityKey = 'address.city';

try {
  const result = searchEntityValue(json, entityKey);
  console.log(`Value of ${entityKey}: ${result.value}`);
  console.log(`Path of ${entityKey}: ${result.path}`);
} catch (err) {
  console.error(err.message);
}
```

This will output:

```
Value of address.city: Anytown
Path of address.city: address.city
```

Here's a recursive JavaScript function that retries a request 3 times before it resolves the promise:

```javascript
function retryRequest(url, retries = 3) {
  return new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open('GET', url);
    xhr.onerror = () => {
      if (retries > 0) {
        retries--;
        retryRequest(url, retries);
      } else {
        reject(new Error('Request failed after 3 retries.'));
      }
    };
    xhr.send();
  });
}
```

This function takes two arguments: `url` (the URL to request) and `retries` (the number of times to retry the request, defaulting to 3). It returns a promise that resolves when the request is successful, or rejects with an error message if the request fails after 3 retries.

To use this function, simply call it with the URL you want to request, like this:

```javascript
retryRequest('https://example.com/api/data')
  .then(response => {
    console.log(response);
  })
  .catch(error => {
    console.error(error);
  });
```

This will make a GET request to the URL "https://example.com/api/data", and retry the request 3 times if it fails. If the request is successful, the response will be logged to the console. If the request fails after 3 retries, an error message will be logged to the console.

