        if let Some(url) = line.parse::<String>() {
            if url.contains("youtube") {
                youtube_urls.push(url);
            }
        }
    }

    println!("Youtube URLs found in file: {:?}", youtube_urls);

    // Download youtube urls using yt-dlp
    // ...

    // Print success message
    println!("Youtube URLs downloaded successfully!");
}
```

